def perceive(data):
    text = data if isinstance(data, str) else str(data)
    quality = 0
    for line in text.splitlines():
        if ":" in line:
            key, value = line.split(":", 1)
            if key.strip() == "quality":
                try:
                    quality = int(value.strip())
                except ValueError:
                    quality = 0
    if quality < 0:
        quality = 0
    if quality > 100:
        quality = 100
    return {"quality": quality}
